import 'package:flutter/material.dart';
import 'package:get/get.dart';

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return GetMaterialApp(
      title: 'Named Routes Demo',
      initialRoute: '/',
      getPages: [
        GetPage(name: '/', page: () => HomePage()),
        GetPage(name: '/details', page: () => DetailsPage()),
        GetPage(name: '/profile/:id', page: () => ProfilePage()),
      ],
      unknownRoute: GetPage(name: '/notfound', page: () => NotFoundPage()),
    );
  }
}

class HomePage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Named Routes')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            ElevatedButton(
              onPressed: () => Get.toNamed('/details', arguments: {'message': 'Hello from home!'}),
              child: Text('Go to Details (with arguments)'),
            ),
            ElevatedButton(
              onPressed: () => Get.toNamed('/profile/42'),
              child: Text('Go to Profile (ID 42)'),
            ),
            ElevatedButton(
              onPressed: () => Get.toNamed('/invalid'),
              child: Text('Go to Invalid (404)'),
            ),
          ],
        ),
      ),
    );
  }
}

class DetailsPage extends StatelessWidget {
  final message = Get.arguments?['message'] ?? 'No message';

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Details')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text('Message: $message'),
            ElevatedButton(
              onPressed: () => Get.back(result: 'closed'),
              child: Text('Go Back'),
            ),
          ],
        ),
      ),
    );
  }
}

class ProfilePage extends StatelessWidget {
  final id = Get.parameters['id'];

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Profile')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text('User ID: $id'),
            ElevatedButton(
              onPressed: () => Get.back(),
              child: Text('Back'),
            ),
          ],
        ),
      ),
    );
  }
}

class NotFoundPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('404')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text('Page not found'),
            ElevatedButton(
              onPressed: () => Get.offAllNamed('/'),
              child: Text('Go Home'),
            ),
          ],
        ),
      ),
    );
  }
}
